export enum Currency {
  USD = 'USD',
  GBP = 'GBP',
  JPY = 'JPY',
  CHF = 'CHF',
  CNY = 'CNY'
}

export enum ExposureType {
  AR = 'Accounts Receivable',
  AP = 'Accounts Payable',
  CASH = 'Cash Balance',
  REVENUE_FORECAST = 'Revenue Forecast',
  COST_FORECAST = 'Cost Forecast',
  DEBT_SERVICE = 'Debt Service'
}

export enum ConfidenceLevel {
  HIGH = 'High (Committed)',
  MEDIUM = 'Medium (Budgeted)',
  LOW = 'Low (Estimated)'
}

export interface ExposureRecord {
  id: string;
  currency: Currency;
  type: ExposureType;
  amountFCY: number; // Positive for inflow, negative for outflow conceptually, but usually stored unsigned and signed by type logic
  date: string; // ISO Date
  confidence: ConfidenceLevel;
  description: string;
}

export interface FXRate {
  currency: Currency;
  rate: number; // EUR base: 1 EUR = X FCY (Indirect Quote)
  volatility: number; // Annualized volatility assumption (synthetic)
  trend: 'appreciating' | 'depreciating' | 'neutral';
}

export interface NetPosition {
  currency: Currency;
  netFCY: number;
  netEUR: number;
  assetsFCY: number;
  liabilitiesFCY: number;
  hedgeRatio: number;
}

export interface SensitivityScenario {
  currency: Currency;
  shockPercentage: number; // e.g., 0.01 for 1%
  impactEUR: number; // Change in EUR value
}

export interface TreasuryRecommendation {
  id: string;
  title: string;
  description: string;
  impact: string; // e.g. "Save ~5k EUR"
  type: 'CONVERSION' | 'TIMING' | 'STRUCTURAL';
  currency: Currency;
}

export interface TimeBucket {
  label: string; // 0-30, 31-90, etc.
  daysMin: number;
  daysMax: number;
}

