import { ExposureRecord, FXRate, NetPosition, SensitivityScenario, TreasuryRecommendation, Currency, ExposureType } from '../types';

// Helper to get rate for a currency
const getRate = (currency: Currency, rates: FXRate[]): number => {
  const rateObj = rates.find(r => r.currency === currency);
  return rateObj ? rateObj.rate : 1;
};

// Calculate Net Positions per Currency
export const calculateNetPositions = (exposures: ExposureRecord[], rates: FXRate[]): NetPosition[] => {
  const positions: Record<string, NetPosition> = {};

  exposures.forEach(exp => {
    if (!positions[exp.currency]) {
      positions[exp.currency] = {
        currency: exp.currency,
        netFCY: 0,
        netEUR: 0,
        assetsFCY: 0,
        liabilitiesFCY: 0,
        hedgeRatio: 0
      };
    }

    const pos = positions[exp.currency];
    const rate = getRate(exp.currency, rates);

    // Convention: amountFCY in the record is already signed (positive for inflow, negative for outflow) 
    // BUT looking at mock data, we are treating amountFCY as signed values.
    // Let's ensure we handle it correctly.

    pos.netFCY += exp.amountFCY;

    if (exp.amountFCY > 0) {
      pos.assetsFCY += exp.amountFCY;
    } else {
      pos.liabilitiesFCY += Math.abs(exp.amountFCY);
    }
  });

  // Finalize calculations
  return Object.values(positions).map(p => {
    const rate = getRate(p.currency, rates);
    return {
      ...p,
      netEUR: p.netFCY / rate,
      // Natural Hedge Ratio: The % of the smaller side covered by the larger side.
      // If Assets 100, Liabs 80 -> Covered 80/100 = 80%.
      // If Assets 20, Liabs 100 -> Covered 20/100 = 20%.
      // Formula: Min(Assets, Liabs) / Max(Assets, Liabs)
      hedgeRatio: (p.assetsFCY === 0 && p.liabilitiesFCY === 0) 
        ? 0 
        : Math.min(p.assetsFCY, p.liabilitiesFCY) / Math.max(p.assetsFCY, p.liabilitiesFCY)
    };
  });
};

// Calculate Sensitivity
export const calculateSensitivity = (position: NetPosition, rates: FXRate[], shockPercent: number): SensitivityScenario => {
  const rate = getRate(position.currency, rates);
  const baseValueEUR = position.netFCY / rate;

  // Shock logic:
  // If Rate is EUR/FCY (e.g. 1.08), and FCY Appreciates (+1%), Rate goes DOWN (1.08 / 1.01 approx or 1.08 * (1-0.01)).
  // Wait, let's be precise.
  // "Shock +1%" typically means the FCY value increases by 1% vs EUR.
  // If FCY strengthens, the Rate (Units of FCY per 1 EUR) decreases.
  // New Rate = Rate / (1 + shockPercent).

  const newRate = rate / (1 + shockPercent);
  const newValueEUR = position.netFCY / newRate;

  return {
    currency: position.currency,
    shockPercentage: shockPercent,
    impactEUR: newValueEUR - baseValueEUR
  };
};

// Generate Recommendations based on rules
export const generateRecommendations = (positions: NetPosition[], exposures: ExposureRecord[], rates: FXRate[]): TreasuryRecommendation[] => {
  const recs: TreasuryRecommendation[] = [];

  positions.forEach(pos => {
    const rateData = rates.find(r => r.currency === pos.currency);
    const absNetEUR = Math.abs(pos.netEUR);

    // Rule 1: High Unhedged Exposure
    if (absNetEUR > 100000 && pos.hedgeRatio < 0.3) {
      recs.push({
        id: `hedging-${pos.currency}`,
        title: `High Open ${pos.currency} Position`,
        description: `Net exposure of ${(pos.netFCY/1000).toFixed(1)}k is largely unhedged (${(pos.hedgeRatio*100).toFixed(0)}% natural hedge).`,
        impact: `Risk of ±${(absNetEUR * 0.05).toFixed(0)} EUR on 5% move`,
        type: 'STRUCTURAL',
        currency: pos.currency
      });
    }

    // Rule 2: Timing/Prepayment for Depreciation
    // If we are Short FCY (Net < 0) and Currency is Appreciating (EUR getting weaker, FCY getting stronger) -> Pay Early
    // If we are Long FCY (Net > 0) and Currency is Depreciating -> Convert Early
    if (rateData?.trend === 'appreciating' && pos.netFCY < 0) {
       recs.push({
        id: `timing-pay-${pos.currency}`,
        title: `Accelerate ${pos.currency} Payables`,
        description: `${pos.currency} is trending stronger. Prepaying liabilities reduces cost basis.`,
        impact: `Potential FX Savings`,
        type: 'TIMING',
        currency: pos.currency
      });
    }

    if (rateData?.trend === 'depreciating' && pos.netFCY > 0) {
       recs.push({
        id: `timing-sell-${pos.currency}`,
        title: `Convert ${pos.currency} Receivables`,
        description: `${pos.currency} is weakening. Spot conversion recommended for cash balances.`,
        impact: `Avoid devaluation loss`,
        type: 'CONVERSION',
        currency: pos.currency
      });
    }
  });

  return recs;
};

import { GoogleGenAI, Type } from "@google/genai";
import { ExposureRecord, NetPosition } from "../types";

// Initialize Gemini Client
// We use a safe initialization that handles the process.env check internally in the usage
const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.warn("Gemini API Key not found");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

export const generateAIInsights = async (
    netPositions: NetPosition[],
    exposures: ExposureRecord[]
): Promise<string> => {
    const ai = getAIClient();
    if (!ai) return "AI services unavailable. Please configure API_KEY.";

    const summaryData = {
        netPositions: netPositions.map(p => ({
            currency: p.currency,
            netEUR: Math.round(p.netEUR),
            hedgeRatio: p.hedgeRatio.toFixed(2)
        })),
        topExposures: exposures.slice(0, 5).map(e => ({
            curr: e.currency,
            amt: e.amountFCY,
            type: e.type,
            desc: e.description
        }))
    };

    const prompt = `
    You are a Treasury Risk Analyst. Analyze the following JSON summary of a company's FX exposures.
    The reporting currency is EUR.

    Data: ${JSON.stringify(summaryData)}

    Provide a concise, professional executive summary (max 3 bullet points) highlighting the biggest risks and one strategic opportunity.
    Focus on net exposure magnitude and low hedge ratios.
    Do not mention the JSON structure, just speak to the financial reality.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: "You are a concise, professional corporate treasurer.",
                thinkingConfig: { thinkingBudget: 0 } 
            }
        });
        return response.text || "No insights generated.";
    } catch (error) {
        console.error("Gemini Error:", error);
        return "Unable to generate AI insights at this time.";
    }
};

export const chatWithTreasuryData = async (
    message: string,
    contextData: any
): Promise<string> => {
    const ai = getAIClient();
    if (!ai) return "AI offline.";

    try {
         const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Context Data: ${JSON.stringify(contextData)}\n\nUser Query: ${message}`,
            config: {
                systemInstruction: "You are a helpful Treasury Assistant. Answer based strictly on the provided context data. Be brief.",
            }
        });
        return response.text || "I couldn't process that.";
    } catch (e) {
        return "Error processing query.";
    }
}

