import React, { useState } from 'react';
import { ExposureRecord, Currency, ExposureType, ConfidenceLevel } from '../types';
import { Trash2, Plus, ArrowUpRight, ArrowDownLeft } from 'lucide-react';

interface ExposureTableProps {
  exposures: ExposureRecord[];
  onAdd: (exposure: Omit<ExposureRecord, 'id'>) => void;
  onDelete: (id: string) => void;
}

const ExposureTable: React.FC<ExposureTableProps> = ({ exposures, onAdd, onDelete }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newExp, setNewExp] = useState<Partial<ExposureRecord>>({
    currency: Currency.USD,
    type: ExposureType.AR,
    confidence: ConfidenceLevel.HIGH,
    amountFCY: 0,
    date: new Date().toISOString().split('T')[0],
    description: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newExp.amountFCY && newExp.date && newExp.description) {
        // Auto-sign logic: if user selects AP/Cost/Debt, ensure negative.
        // If AR/Revenue/Cash, ensure positive. 
        // Or we just trust the input? Let's strictly enforce sign based on Type for UX simplicity.
        let amt = Math.abs(newExp.amountFCY);
        if ([ExposureType.AP, ExposureType.COST_FORECAST, ExposureType.DEBT_SERVICE].includes(newExp.type as ExposureType)) {
            amt = -amt;
        }

        onAdd({
            currency: newExp.currency as Currency,
            type: newExp.type as ExposureType,
            amountFCY: amt,
            date: newExp.date as string,
            confidence: newExp.confidence as ConfidenceLevel,
            description: newExp.description as string
        });
        setIsAdding(false);
        setNewExp({ ...newExp, amountFCY: 0, description: '' });
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
            <h3 className="text-xl font-bold text-slate-900">Exposure Register</h3>
            <p className="text-sm text-slate-500">Manage all balance sheet and forecasted items</p>
        </div>
        <button 
            onClick={() => setIsAdding(!isAdding)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors"
        >
            <Plus size={16} />
            New Exposure
        </button>
      </div>

      {isAdding && (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4">
            <h4 className="font-semibold mb-4 text-slate-700">Add New Record</h4>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <select 
                    className="p-2 border rounded text-sm bg-slate-50"
                    value={newExp.currency}
                    onChange={e => setNewExp({...newExp, currency: e.target.value as Currency})}
                >
                    {Object.values(Currency).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <select 
                    className="p-2 border rounded text-sm bg-slate-50"
                    value={newExp.type}
                    onChange={e => setNewExp({...newExp, type: e.target.value as ExposureType})}
                >
                    {Object.values(ExposureType).map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <input 
                    type="number" 
                    placeholder="Amount (FCY)" 
                    className="p-2 border rounded text-sm"
                    required
                    onChange={e => setNewExp({...newExp, amountFCY: parseFloat(e.target.value)})}
                />
                <input 
                    type="date" 
                    className="p-2 border rounded text-sm"
                    required
                    value={newExp.date}
                    onChange={e => setNewExp({...newExp, date: e.target.value})}
                />
                 <select 
                    className="p-2 border rounded text-sm bg-slate-50"
                    value={newExp.confidence}
                    onChange={e => setNewExp({...newExp, confidence: e.target.value as ConfidenceLevel})}
                >
                    {Object.values(ConfidenceLevel).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <input 
                    type="text" 
                    placeholder="Description" 
                    className="p-2 border rounded text-sm"
                    required
                    value={newExp.description}
                    onChange={e => setNewExp({...newExp, description: e.target.value})}
                />
                <div className="md:col-span-3 flex justify-end gap-2 mt-2">
                    <button type="button" onClick={() => setIsAdding(false)} className="px-4 py-2 text-sm text-slate-600 hover:bg-slate-100 rounded">Cancel</button>
                    <button type="submit" className="px-4 py-2 text-sm bg-slate-900 text-white rounded hover:bg-slate-800">Save Record</button>
                </div>
            </form>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                <tr>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4">Currency</th>
                <th className="px-6 py-4">Description</th>
                <th className="px-6 py-4">Type</th>
                <th className="px-6 py-4 text-right">Amount (FCY)</th>
                <th className="px-6 py-4">Confidence</th>
                <th className="px-6 py-4">Actions</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {exposures.length === 0 ? (
                    <tr><td colSpan={7} className="px-6 py-8 text-center text-slate-400">No exposures recorded.</td></tr>
                ) : (
                    exposures.map((exp) => (
                    <tr key={exp.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 font-mono text-slate-600">{exp.date}</td>
                        <td className="px-6 py-4 font-bold text-slate-700">{exp.currency}</td>
                        <td className="px-6 py-4 text-slate-900">{exp.description}</td>
                        <td className="px-6 py-4">
                            <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-slate-100 text-slate-600">
                                {exp.type}
                            </span>
                        </td>
                        <td className={`px-6 py-4 text-right font-mono font-medium ${exp.amountFCY > 0 ? 'text-green-600' : 'text-red-600'}`}>
                            {exp.amountFCY > 0 ? <ArrowUpRight className="inline w-3 h-3 mr-1" /> : <ArrowDownLeft className="inline w-3 h-3 mr-1" />}
                            {Math.abs(exp.amountFCY).toLocaleString()}
                        </td>
                        <td className="px-6 py-4">
                            <span className={`text-xs px-2 py-1 rounded border ${
                                exp.confidence.includes('High') ? 'bg-green-50 border-green-100 text-green-700' : 
                                exp.confidence.includes('Medium') ? 'bg-amber-50 border-amber-100 text-amber-700' :
                                'bg-slate-50 border-slate-100 text-slate-600'
                            }`}>
                                {exp.confidence.split(' ')[0]}
                            </span>
                        </td>
                        <td className="px-6 py-4">
                            <button 
                                onClick={() => onDelete(exp.id)}
                                className="text-slate-400 hover:text-red-500 transition-colors"
                            >
                                <Trash2 size={16} />
                            </button>
                        </td>
                    </tr>
                    ))
                )}
            </tbody>
            </table>
        </div>
      </div>
    </div>
  );
};

export default ExposureTable;

