import React, { useState } from 'react';
import { NetPosition, FXRate } from '../types';
import { calculateSensitivity } from '../services/calculationEngine';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface SensitivityAnalysisProps {
  netPositions: NetPosition[];
  rates: FXRate[];
}

const SensitivityAnalysis: React.FC<SensitivityAnalysisProps> = ({ netPositions, rates }) => {
  const [shockSize, setShockSize] = useState(0.05); // 5% default

  const data = netPositions
    .filter(p => Math.abs(p.netEUR) > 1000) // Filter trivial amounts
    .map(p => {
        const up = calculateSensitivity(p, rates, shockSize);
        const down = calculateSensitivity(p, rates, -shockSize);
        return {
            name: p.currency,
            'Rate +X% (FCY Weakens)': Math.round(up.impactEUR),
            'Rate -X% (FCY Strengthens)': Math.round(down.impactEUR),
        };
    });

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
            <div>
                <h3 className="text-lg font-bold text-slate-900">Portfolio Sensitivity Analysis</h3>
                <p className="text-sm text-slate-500">Projected P&L impact of FX rate movements</p>
            </div>

            <div className="flex items-center gap-3 bg-slate-50 p-1 rounded-lg border border-slate-200">
                {[0.01, 0.05, 0.10].map((val) => (
                    <button
                        key={val}
                        onClick={() => setShockSize(val)}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${
                            shockSize === val 
                            ? 'bg-white text-blue-600 shadow-sm' 
                            : 'text-slate-500 hover:text-slate-700'
                        }`}
                    >
                        ±{(val * 100).toFixed(0)}%
                    </button>
                ))}
            </div>
        </div>

        <div className="h-96 w-full">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} />
                    <YAxis 
                        axisLine={false} 
                        tickLine={false} 
                        tickFormatter={(val) => `€${val/1000}k`} 
                    />
                    <Tooltip 
                        formatter={(value: number) => `€${value.toLocaleString()}`}
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        cursor={{fill: '#f1f5f9'}}
                    />
                    <Legend wrapperStyle={{paddingTop: '20px'}} />
                    <Bar name={`FCY Appreciates ${shockSize*100}% (Gain/Loss)`} dataKey="Rate -X% (FCY Strengthens)" fill="#10b981" radius={[4, 4, 0, 0]} />
                    <Bar name={`FCY Depreciates ${shockSize*100}% (Gain/Loss)`} dataKey="Rate +X% (FCY Weakens)" fill="#ef4444" radius={[4, 4, 0, 0]} />
                </BarChart>
            </ResponsiveContainer>
        </div>
        <div className="mt-6 text-sm text-slate-500 bg-blue-50 p-4 rounded-lg border border-blue-100">
            <span className="font-bold text-blue-800">Note:</span> Positive bars indicate a P&L Gain in EUR. Negative bars indicate a P&L Loss.
            <ul className="list-disc list-inside mt-2 space-y-1 ml-2">
                <li>If you are <span className="font-semibold">Long</span> a currency (Net Assets), you gain when FCY appreciates (Green Bar positive).</li>
                <li>If you are <span className="font-semibold">Short</span> a currency (Net Liabilities), you lose when FCY appreciates (Green Bar negative).</li>
            </ul>
        </div>
      </div>
    </div>
  );
};

export default SensitivityAnalysis;

