import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ExposureTable from './components/ExposureTable';
import SensitivityAnalysis from './components/SensitivityAnalysis';
import AIInsights from './components/AIInsights';
import { MOCK_EXPOSURES, INITIAL_RATES } from './constants';
import { ExposureRecord, NetPosition, TreasuryRecommendation } from './types';
import { calculateNetPositions, generateRecommendations } from './services/calculationEngine';

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [exposures, setExposures] = useState<ExposureRecord[]>(MOCK_EXPOSURES);
  const [rates] = useState(INITIAL_RATES); // In real app, we'd fetch these

  // Derived State
  const [netPositions, setNetPositions] = useState<NetPosition[]>([]);
  const [recommendations, setRecommendations] = useState<TreasuryRecommendation[]>([]);

  // Recalculate on exposure change
  useEffect(() => {
    const positions = calculateNetPositions(exposures, rates);
    setNetPositions(positions);
    setRecommendations(generateRecommendations(positions, exposures, rates));
  }, [exposures, rates]);

  const handleAddExposure = (newExp: Omit<ExposureRecord, 'id'>) => {
    const record: ExposureRecord = {
        ...newExp,
        id: Math.random().toString(36).substr(2, 9)
    };
    setExposures([...exposures, record]);
  };

  const handleDeleteExposure = (id: string) => {
    setExposures(exposures.filter(e => e.id !== id));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard netPositions={netPositions} recommendations={recommendations} rates={rates} exposures={exposures} />;
      case 'exposures':
        return <ExposureTable exposures={exposures} onAdd={handleAddExposure} onDelete={handleDeleteExposure} />;
      case 'sensitivity':
        return <SensitivityAnalysis netPositions={netPositions} rates={rates} />;
      case 'insights':
        return <AIInsights netPositions={netPositions} exposures={exposures} />;
      default:
        return <Dashboard netPositions={netPositions} recommendations={recommendations} rates={rates} exposures={exposures} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {renderContent()}
    </Layout>
  );
}

export default App;

